  /* ===================== HELPER FUNCTIONS ===================== */

  function getMonsterById(id) {
    return MONSTERS_DB.find(m => m.id === id) || null;
  }

  function getWeaponById(id) {
    return WEAPONS_DB.find(w => w.id === id) || null;
  }

  function getItemById(id) {
    return ITEMS_DB.find(i => i.id === id) || null;
  }

  function getArmorById(id) {
    return ARMOR_DB.find(a => a.id === id) || null;
  }

  function getRegionById(id) {
    return MAP_REGIONS.find(r => r.id === id) || null;
  }

  function getRegionMonsters(regionId) {
    const region = getRegionById(regionId);
    if (!region) return [];
    return region.monsters.map(id => getMonsterById(id)).filter(Boolean);
  }

  function getEquippableWeapons(playerClass) {
    const cfg = CLASS_CONFIG[playerClass];
    if (!cfg || !cfg.weapon_cats.length) return WEAPONS_DB;
    return WEAPONS_DB.filter(w => cfg.weapon_cats.includes(w.category));
  }

  function getEquippableArmor(playerClass) {
    const cfg = CLASS_CONFIG[playerClass];
    if (!cfg) return ARMOR_DB;
    return ARMOR_DB.filter(a => cfg.armor_classes.includes(a.class));
  }

  function calcExpForLevel(level) {
    return EXP_TABLE[Math.min(level, EXP_TABLE.length - 1)] || 0;
  }

  function getItemByName(name) {
    return ITEMS_DB.find(i => i.name === name) || null;
  }

  function rollDrops(monster) {
    const drops = [];
    const d = monster.drops || {};
    const allDropNames = [
      ...(d.common_items || []),
      ...(d.recovery_items || []),
      ...(d.gems || []),
    ];
    // Roll each potential drop
    allDropNames.forEach(name => {
      const itemData = ITEMS_DB.find(i => i.name === name);
      const rate = itemData ? itemData.base_rate / 100 : 0.05;
      if (Math.random() < rate) {
        drops.push({ name, itemData });
      }
    });
    // Armor drops
    (d.armors || []).forEach(armorName => {
      const armorData = ARMOR_DB.find(a => a.name === armorName);
      if (armorData && Math.random() < 0.08) {
        drops.push({ name: armorName, armorData });
      }
    });
    return drops;
  }

  /* ===================== PUBLIC API ===================== */
  window.GAME_DATA = {
    WEAPONS_DB,
    ITEMS_DB,
    ARMOR_DB,
    MONSTERS_DB,
    MAP_REGIONS,
    CLASS_CONFIG,
    ATTR_COLORS,
    SLOT_LABELS,
    EXP_TABLE,
    DEFAULT_STATE,
    // Helper functions
    getMonsterById,
    getWeaponById,
    getItemById,
    getArmorById,
    getRegionById,
    getRegionMonsters,
    getEquippableWeapons,
    getEquippableArmor,
    calcExpForLevel,
    getItemByName,
    rollDrops,
  };

